#!/usr/bin/env node
/**
 * Knowledge Graph Validation Script
 * Validates structural graph, domain graph, and layer definitions for OpenCoreSDK
 */

const fs = require('fs');

const VALID_NODE_TYPES = [
  'file', 'function', 'class', 'module', 'concept', 'config', 'document',
  'service', 'table', 'endpoint', 'pipeline', 'schema', 'resource',
  'domain', 'flow', 'step'
];

const VALID_EDGE_TYPES = [
  'imports', 'exports', 'contains', 'inherits', 'implements', 'calls',
  'subscribes', 'publishes', 'middleware', 'reads_from', 'writes_to',
  'transforms', 'validates', 'depends_on', 'tested_by', 'configures',
  'related', 'similar_to', 'deploys', 'serves', 'migrates', 'documents',
  'provisions', 'routes', 'defines_schema', 'triggers', 'contains_flow',
  'flow_step', 'cross_domain'
];

const VALID_COMPLEXITY = ['simple', 'moderate', 'complex'];
const VALID_DIRECTIONS = ['forward', 'backward', 'bidirectional'];

const FILE_LEVEL_TYPES = ['file', 'config', 'document', 'service', 'pipeline', 'table', 'schema', 'resource', 'endpoint'];

function main() {
  const graphPath = process.argv[2];
  const outputPath = process.argv[3];

  if (!graphPath || !outputPath) {
    console.error('Usage: node ua-graph-validate.js <graph-file> <output-file>') > process.stderr;
    process.exit(1);
  }

  let graphData;
  try {
    const content = fs.readFileSync(graphPath, 'utf8');
    graphData = JSON.parse(content);
  } catch (err) {
    console.error(`Error reading or parsing graph file: ${err.message}`, { file: graphPath }) > process.stderr;
    process.exit(1);
  }

  const issues = [];
  const warnings = [];
  const stats = {
    totalNodes: 0,
    totalEdges: 0,
    totalLayers: 0,
    tourSteps: 0,
    nodeTypes: {},
    edgeTypes: {}
  };

  // Detect if this is a domain graph
  const isDomainGraph = graphData.nodes && graphData.nodes.some(n => n.type === 'domain' || n.type === 'flow' || n.type === 'step');

  // ========== CHECK 1: Schema Validation ==========
  let nodes = [];
  let edges = [];

  if (graphData.fileNodes) {
    // Structural graph format
    nodes = graphData.fileNodes || [];
    edges = graphData.allEdges || [];
  } else if (graphData.nodes) {
    // Domain graph format
    nodes = graphData.nodes || [];
    edges = graphData.edges || [];
  }

  stats.totalNodes = nodes.length;
  stats.totalEdges = edges.length;

  // Validate nodes
  const nodeIds = new Set();
  for (let i = 0; i < nodes.length; i++) {
    const node = nodes[i];
    const nodeIndex = `node[${i}]`;

    // Required fields
    if (!node.id) {
      issues.push(`${nodeIndex}: Missing required field 'id'`);
    } else {
      if (nodeIds.has(node.id)) {
        issues.push(`${nodeIndex}: Duplicate node ID '${node.id}'`);
      }
      nodeIds.add(node.id);

      // Check ID prefix matches type
      if (node.type) {
        const expectedPrefix = node.type + ':';
        if (!node.id.startsWith(expectedPrefix) && !node.id.startsWith('file:') && !node.id.startsWith('config:') && !node.id.startsWith('document:') && !node.id.startsWith('service:')) {
          // Allow some flexibility - just warn
        }
      }
    }

    if (!node.type) {
      issues.push(`${nodeIndex}: Missing required field 'type'`);
    } else if (!VALID_NODE_TYPES.includes(node.type)) {
      issues.push(`${nodeIndex}: Invalid node type '${node.type}'. Valid types: ${VALID_NODE_TYPES.join(', ')}`);
    }

    if (!node.name) {
      issues.push(`${nodeIndex}: Missing required field 'name'`);
    }

    if (!node.summary) {
      issues.push(`${nodeIndex}: Missing required field 'summary'`);
    } else if (node.summary.length < 10) {
      warnings.push(`${nodeIndex} ('${node.name}'): Summary is very short (${node.summary.length} chars)`);
    }

    if (!node.tags || !Array.isArray(node.tags) || node.tags.length === 0) {
      issues.push(`${nodeIndex}: Missing or empty 'tags' array`);
    } else {
      for (const tag of node.tags) {
        if (typeof tag !== 'string' || tag !== tag.toLowerCase() || tag.includes('_')) {
          warnings.push(`${nodeIndex}: Tag '${tag}' should be lowercase and hyphenated`);
        }
      }
    }

    if (!node.complexity) {
      if (node.type === 'domain' || node.type === 'flow' || node.type === 'step') {
        issues.push(`${nodeIndex}: Missing required field 'complexity'`);
      }
    } else if (!VALID_COMPLEXITY.includes(node.complexity)) {
      issues.push(`${nodeIndex}: Invalid complexity '${node.complexity}'. Valid values: ${VALID_COMPLEXITY.join(', ')}`);
    }

    // Track node types
    if (node.type) {
      stats.nodeTypes[node.type] = (stats.nodeTypes[node.type] || 0) + 1;
    }
  }

  // Validate edges
  for (let i = 0; i < edges.length; i++) {
    const edge = edges[i];
    const edgeIndex = `edge[${i}]`;

    if (!edge.source) {
      issues.push(`${edgeIndex}: Missing required field 'source'`);
    }

    if (!edge.target) {
      issues.push(`${edgeIndex}: Missing required field 'target'`);
    }

    if (!edge.type) {
      issues.push(`${edgeIndex}: Missing required field 'type'`);
    } else if (!VALID_EDGE_TYPES.includes(edge.type)) {
      issues.push(`${edgeIndex}: Invalid edge type '${edge.type}'. Valid types: ${VALID_EDGE_TYPES.join(', ')}`);
    }

    if (!edge.direction) {
      issues.push(`${edgeIndex}: Missing required field 'direction'`);
    } else if (!VALID_DIRECTIONS.includes(edge.direction)) {
      issues.push(`${edgeIndex}: Invalid direction '${edge.direction}'. Valid values: ${VALID_DIRECTIONS.join(', ')}`);
    }

    if (edge.weight === undefined || edge.weight === null) {
      issues.push(`${edgeIndex}: Missing required field 'weight'`);
    } else if (typeof edge.weight !== 'number' || edge.weight < 0.0 || edge.weight > 1.0) {
      issues.push(`${edgeIndex}: Edge weight must be between 0.0 and 1.0, got '${edge.weight}'`);
    }

    // Self-referencing edge check
    if (edge.source && edge.target && edge.source === edge.target) {
      warnings.push(`${edgeIndex}: Self-referencing edge (source === target)`);
    }

    // Track edge types
    if (edge.type) {
      stats.edgeTypes[edge.type] = (stats.edgeTypes[edge.type] || 0) + 1;
    }
  }

  // ========== CHECK 2: Referential Integrity ==========
  for (let i = 0; i < edges.length; i++) {
    const edge = edges[i];
    const edgeIndex = `edge[${i}]`;

    if (edge.source && !nodeIds.has(edge.source)) {
      issues.push(`${edgeIndex}: Edge references non-existent source node '${edge.source}'`);
    }
    if (edge.target && !nodeIds.has(edge.target)) {
      issues.push(`${edgeIndex}: Edge references non-existent target node '${edge.target}'`);
    }
  }

  // ========== CHECK 3: Completeness ==========
  if (nodes.length === 0) {
    issues.push('Graph has zero nodes');
  }
  if (edges.length === 0) {
    issues.push('Graph has zero edges');
  }

  // Layer check (if layers exist in the graph file)
  let layers = [];
  if (graphData.layers) {
    layers = graphData.layers;
    stats.totalLayers = layers.length;

    if (layers.length === 0 && !isDomainGraph) {
      issues.push('Graph has zero layers');
    }

    for (let i = 0; i < layers.length; i++) {
      const layer = layers[i];
      const layerIndex = `layer[${i}]`;

      if (!layer.nodeIds || layer.nodeIds.length === 0) {
        warnings.push(`${layerIndex} ('${layer.name || layer.id}'): Layer has empty nodeIds array`);
      }

      for (const nodeId of (layer.nodeIds || [])) {
        if (!nodeIds.has(nodeId)) {
          issues.push(`${layerIndex}: Layer references non-existent node '${nodeId}'`);
        }
      }
    }
  }

  // Tour check
  let tour = [];
  if (graphData.tour) {
    tour = graphData.tour;
    stats.tourSteps = tour.length;

    if (tour.length === 0 && !isDomainGraph) {
      issues.push('Graph has zero tour steps');
    }

    if (tour.length > 0 && tour.length < 5) {
      warnings.push(`Tour has only ${tour.length} steps (expected 5-15)`);
    }
    if (tour.length > 15) {
      warnings.push(`Tour has ${tour.length} steps (expected 5-15)`);
    }

    const orderValues = new Set();
    for (let i = 0; i < tour.length; i++) {
      const step = tour[i];

      if (step.nodeIds && step.nodeIds.length === 0) {
        warnings.push(`tour[${i}]: Step has empty nodeIds array`);
      }

      if (step.order !== undefined) {
        if (orderValues.has(step.order)) {
          issues.push(`tour[${i}]: Duplicate tour order value ${step.order}`);
        }
        orderValues.add(step.order);
      }

      // Check nodeId references in tour
      if (step.nodeIds) {
        for (const nodeId of step.nodeIds) {
          if (!nodeIds.has(nodeId)) {
            issues.push(`tour[${i}]: Tour step references non-existent node '${nodeId}'`);
          }
        }
      }
    }
  }

  // ========== CHECK 4: Layer Coverage ==========
  const fileLevelNodes = nodes.filter(n => FILE_LEVEL_TYPES.includes(n.type));
  const nodesInLayers = new Set();

  for (const layer of layers) {
    for (const nodeId of (layer.nodeIds || [])) {
      if (nodesInLayers.has(nodeId)) {
        issues.push(`Node '${nodeId}' appears in multiple layers`);
      }
      nodesInLayers.add(nodeId);
    }
  }

  // For structural graphs, check file-level nodes are in exactly one layer
  if (!isDomainGraph && layers.length > 0) {
    for (const node of fileLevelNodes) {
      if (!nodesInLayers.has(node.id)) {
        issues.push(`File-level node '${node.id}' is not assigned to any layer`);
      }
    }
  }

  // ========== CHECK 5: Uniqueness ==========
  // Already done in CHECK 1

  // ========== CHECK 6: Tour Validation ==========
  // Already done in CHECK 3

  // ========== CHECK 7: Quality Checks ==========
  // Orphan nodes
  const connectedNodes = new Set();
  for (const edge of edges) {
    if (edge.source) connectedNodes.add(edge.source);
    if (edge.target) connectedNodes.add(edge.target);
  }

  for (const node of nodes) {
    if (!connectedNodes.has(node.id)) {
      warnings.push(`Node '${node.id}' has no edges connecting to it (orphan)`);
    }
  }

  // Self-referencing edges (already done in CHECK 1)

  // ========== CHECK 8: Non-Code Node Quality ==========
  // Service nodes should have deploys or depends_on edges
  const serviceNodes = nodes.filter(n => n.type === 'service');
  for (const node of serviceNodes) {
    const hasDeploys = edges.some(e => e.source === node.id && e.type === 'deploys');
    const hasDepends = edges.some(e => e.source === node.id && e.type === 'depends_on');
    if (!hasDeploys && !hasDepends) {
      warnings.push(`Service node '${node.id}' has no 'deploys' or 'depends_on' edges`);
    }
  }

  // Document nodes should have documents edges
  const documentNodes = nodes.filter(n => n.type === 'document');
  for (const node of documentNodes) {
    const hasDocuments = edges.some(e => e.source === node.id && e.type === 'documents');
    if (!hasDocuments) {
      warnings.push(`Document node '${node.id}' has no 'documents' edges`);
    }
  }

  // Pipeline nodes should have triggers edges
  const pipelineNodes = nodes.filter(n => n.type === 'pipeline');
  for (const node of pipelineNodes) {
    const hasTriggers = edges.some(e => e.source === node.id && e.type === 'triggers');
    if (!hasTriggers) {
      warnings.push(`Pipeline node '${node.id}' has no 'triggers' edges`);
    }
  }

  // Domain nodes should have contains_flow edges
  const domainNodes = nodes.filter(n => n.type === 'domain');
  for (const node of domainNodes) {
    const hasContainsFlow = edges.some(e => e.source === node.id && e.type === 'contains_flow');
    if (!hasContainsFlow) {
      warnings.push(`Domain node '${node.id}' has no 'contains_flow' edges`);
    }
  }

  // Flow nodes should have flow_step edges
  const flowNodes = nodes.filter(n => n.type === 'flow');
  for (const node of flowNodes) {
    const hasFlowStep = edges.some(e => e.source === node.id && e.type === 'flow_step');
    if (!hasFlowStep) {
      warnings.push(`Flow node '${node.id}' has no 'flow_step' edges`);
    }
  }

  // ========== CHECK 9: Node Type / ID Prefix Consistency ==========
  for (const node of nodes) {
    if (!node.id || !node.type) continue;

    const typePrefixes = {
      'file': 'file:',
      'function': 'function:',
      'class': 'class:',
      'module': 'module:',
      'concept': 'concept:',
      'config': 'config:',
      'document': 'document:',
      'service': 'service:',
      'table': 'table:',
      'endpoint': 'endpoint:',
      'pipeline': 'pipeline:',
      'schema': 'schema:',
      'resource': 'resource:',
      'domain': 'domain:',
      'flow': 'flow:',
      'step': 'step:'
    };

    const expectedPrefix = typePrefixes[node.type];
    if (expectedPrefix && !node.id.startsWith(expectedPrefix)) {
      warnings.push(`Node '${node.id}' has type '${node.type}' but ID does not start with '${expectedPrefix}'`);
    }
  }

  // ========== Output Results ==========
  const result = {
    scriptCompleted: true,
    issues,
    warnings,
    stats
  };

  try {
    fs.writeFileSync(outputPath, JSON.stringify(result, null, 2));
    console.error('Validation complete. Results written to:', outputPath);
  } catch (err) {
    console.error('Error writing output file:', err.message) > process.stderr;
    process.exit(1);
  }

  process.exit(0);
}

main();

