  "issues": [],
  "warnings": [
    "Tag 'x86_64' should be lowercase and hyphenated (use 'x86-64' instead)",
    "Domain node 'domain:thread-control' has no 'contains_flow' edges - thread-control domain has no associated flow nodes",
    "Domain node 'domain:multi-architecture' has no 'contains_flow' edges - multi-architecture domain has no associated flow nodes",
    "Domain node 'domain:inject-mode' has no 'contains_flow' edges - inject-mode domain has no associated flow nodes"
  ],
  "stats": {
    "totalNodes": 30,
    "totalEdges": 29,
    "totalLayers": 8,
    "tourSteps": 10,
    "nodeTypes": {
      "domain": 6,
      "flow": 4,
      "step": 20
    },
    "edgeTypes": {
      "contains_flow": 4,
      "flow_step": 20,
      "cross_domain": 5
    }
  }
}
